import React, { useEffect, useState, useCallback } from "react";
import style from "./Dashboard.module.css";

const Dashboard = () => {
  const user = JSON.parse(localStorage.getItem("user"));

  const [events, setEvents] = useState([]);

  const [form, setForm] = useState({
    title: "",
    description: "",
    location: "",
    date: "",
    category: "IT",
    image: ""
  });

  // =========================
  // 📥 ЗАГРУЗКА СОБЫТИЙ ОРГАНИЗАТОРА
  // =========================
  const loadEvents = useCallback(() => {
    fetch(`http://localhost:5000/organizer/events/${user.id}`)
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) {
          setEvents(data);
        } else {
          setEvents([]);
        }
      })
      .catch(err => console.error(err));
  }, [user.id]);

  useEffect(() => {
    loadEvents();
  }, [loadEvents]);

  // =========================
  //СОЗДАТЬ СОБЫТИЕ
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      const res = await fetch("http://localhost:5000/admin/events", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify({
          ...form,
          user_id: user.id // 🔥 ВАЖНО
        })
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      alert("Подія створена 🎉");

      setForm({
        title: "",
        description: "",
        location: "",
        date: "",
        category: "IT",
        image: ""
      });

      loadEvents();

    } catch (err) {
      console.error(err);
    }
  };

  // =========================
  // 🗑 УДАЛЕНИЕ
  // =========================
  const handleDelete = async (id) => {
    if (!window.confirm("Видалити подію?")) return;

    try {
      const res = await fetch(`http://localhost:5000/events/${id}`, {
        method: "DELETE"
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      setEvents(prev => prev.filter(event => event.id !== id));

    } catch (err) {
      console.error(err);
    }
  };

  return (
    <div className={style.dashboard-page}>

      <h1>Кабінет організатора 👤</h1>

      {/* ========================= */}
      {/* 📋 МОИ СОБЫТИЯ */}
      {/* ========================= */}
      <div className={style.dashboard-events}>
        <h2>Мої події</h2>

        {events.length > 0 ? (
          events.map(event => (
            <div key={event.id} className={style.event-card}>

              <div>
                <h3>{event.title}</h3>
                <p>{event.location}</p>
                <p>{new Date(event.date).toLocaleString()}</p>
              </div>

              <button
                className={style.delete-btn}
                onClick={() => handleDelete(event.id)}
              >
                Видалити
              </button>

            </div>
          ))
        ) : (
          <p>У вас ще немає подій</p>
        )}
      </div>

      {/* ========================= */}
      {/* ➕ СОЗДАТЬ СОБЫТИЕ */}
      {/* ========================= */}
      <div className={style.dashboard-form}>
        <h2>Створити подію</h2>

        <form onSubmit={handleSubmit} autoComplete="off">

          <input
            placeholder="Назва"
            value={form.title}
            onChange={(e) =>
              setForm({ ...form, title: e.target.value })
            }
          />

          <input
            placeholder="Опис"
            value={form.description}
            onChange={(e) =>
              setForm({ ...form, description: e.target.value })
            }
          />

          <input
            placeholder="Місто"
            value={form.location}
            onChange={(e) =>
              setForm({ ...form, location: e.target.value })
            }
          />

          <input
            type="datetime-local"
            value={form.date}
            onChange={(e) =>
              setForm({ ...form, date: e.target.value })
            }
          />

          <select
            value={form.category}
            onChange={(e) =>
              setForm({ ...form, category: e.target.value })
            }
          >
            <option>IT</option>
            <option>Business</option>
            <option>Design</option>
            <option>Marketing</option>
            <option>Education</option>
          </select>

          <input
            placeholder="URL картинки"
            value={form.image}
            onChange={(e) =>
              setForm({ ...form, image: e.target.value })
            }
          />

          <button type="submit">Створити</button>

        </form>
      </div>

    </div>
  );
};

export default Dashboard;
